SELECT COUNT(DISTINCT S.PK_SIAPE) FROM SERVIDOR S JOIN CARGO C ON C.FK_SIAPE = S.PK_SIAPE WHERE LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(C.SIGLA_CAMPUS) = LOWER('for') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%educa%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%fisica%') AND C.DATA_ENTRADA <= '2024-06-30' AND (C.DATA_SAIDA IS NULL OR C.DATA_SAIDA >= '2024-01-01')